import java.nio.charset.StandardCharsets;

/**
 * AESService provides utility methods for AES encryption.
 * This implementation uses AES in ECB mode with PKCS5Padding.
 */
public class AESService {

    private static final String ALGORITHM = "AES";
    private static final String TRANSFORMATION = "AES/ECB/PKCS5Padding";
    private static final char[] HEX_ARRAY = "0123456789abcdef".toCharArray();

    /**
     * Encrypts the provided byte array using the AES algorithm and returns a Hexadecimal string.
     *
     * @param key  The encryption key string (should be 16, 24, or 32 characters for AES-128/192/256).
     * @param data The plaintext message as a byte array.
     * @return The encrypted ciphertext represented as a Hex string.
     * @throws IllegalArgumentException if key or data is null.
     * @throws RuntimeException if any encryption error occurs (e.g., invalid key length).
     */
    public static String encrypt(String key, byte[] data) {
        if (key == null || data == null) {
            throw new IllegalArgumentException("Encryption key and data must not be null.");
        }

        try {
            // Convert key string to bytes and create SecretKeySpec
            byte[] keyBytes = key.getBytes(StandardCharsets.UTF_8);
            SecretKeySpec secretKey = new SecretKeySpec(keyBytes, ALGORITHM);

            // Initialize Cipher for AES encryption
            Cipher cipher = Cipher.getInstance(TRANSFORMATION);
            cipher.init(Cipher.ENCRYPT_MODE, secretKey);

            // Encrypt the data
            byte[] encryptedBytes = cipher.doFinal(data);

            // Convert the byte array to a Hexadecimal string for transmission
            return bytesToHex(encryptedBytes);
        } catch (Exception e) {
            // Wrap checked exceptions in a RuntimeException for cleaner service-layer handling
            throw new RuntimeException("Error occurred during AES encryption: " + e.getMessage(), e);
        }
    }

    /**
     * Efficiently converts a byte array to a Hexadecimal string.
     *
     * @param bytes The byte array to convert.
     * @return The resulting Hex string.
     */
    private static String bytesToHex(byte[] bytes) {
        char[] hexChars = new char[bytes.length * 2];
        for (int j = 0; j < bytes.length; j++) {
            int v = bytes[j] & 0xFF;
            hexChars[j * 2] = HEX_ARRAY[v >>> 4];
            hexChars[j * 2 + 1] = HEX_ARRAY[v & 0x0F];
        }
        return new String(hexChars);
    }
}

